2	  config,
3	  pkgs,
4	  inputs,
5	  lib,
6	  ...
7	}:
8	
9	{
10	  imports = [ ./common.nix ];
11	
12	  options.cosmo.antigravity.enable = lib.mkOption {
13	    type = lib.types.bool;
14	    default = false;
15	    description = ''
16	      Whether to install the native (non-FHS) Antigravity IDE
17	      (pkgs.antigravity, autoPatchelf-based). Unfree; requires
18	      nixpkgs.config.allowUnfree on the host.
19	    '';
20	  };
21	
22	  options.cosmo.klaus.pollFallback = lib.mkOption {
23	    type = lib.types.bool;
24	    default = false;
25	    description = ''
26	      Whether klaus should fall back to GitHub API polling for pipeline events.
27	      Default false relies on the Tailscale webhook relay (classic-laddie).
28	      Set true on hosts that cannot reach the relay (e.g. corp machines with no
29	      Tailscale), otherwise the pipeline receives no events.
30	    '';
31	  };
32	
33	  options.cosmo.standaloneHomeManager.autoUpgrade = {
34	    enable = lib.mkOption {
35	      type = lib.types.bool;
36	      default = false;
37	      description = ''
38	        Whether to install a systemd *user* timer that rebuilds this standalone
39	        home-manager configuration from cosmo upstream once a day. This is the
40	        standalone-home-manager analogue of NixOS `system.autoUpgrade`, for
41	        home-manager installs on non-NixOS hosts (e.g. the corp Debian box /
42	        Crostini) where there is no system-level rebuild.
43	
44	        Do NOT enable this where NixOS `system.autoUpgrade` applies: on NixOS the
45	        system rebuild already manages home-manager, and a standalone
46	        `home-manager switch` from a user timer would create a competing,
47	        NixOS-unmanaged generation. (The service also hard-guards against this at
48	        runtime by no-opping when `/etc/NIXOS` exists.)
49	      '';
50	    };
51	    flakeRef = lib.mkOption {
52	      type = lib.types.str;
53	      default = "github:patflynn/cosmo";
54	      description = "Flake reference to rebuild from. The home config is selected as <flakeRef>#<username>@<short-hostname>.";
55	    };
56	    onCalendar = lib.mkOption {
57	      type = lib.types.str;
58	      default = "daily";
59	      description = "systemd OnCalendar schedule for the daily rebuild.";
60	    };
61	  };
62	
63	  config = {
64	    # Development Tools
65	    home.packages =
66	      with pkgs;
67	      [
68	        # Language Servers & Runtimes
69	        nixd # Nix LSP
70	        python3
71	        nodejs
72	
73	        # Build Tools
74	        gnumake
75	        gcc
76	        openssl
77	
78	        # CLIs
79	        claude-code # Anthropic's CLI
80	        github-cli # GitHub CLI (gh)
81	        jujutsu # Modern VCS (jj)
82	
83	        # Age tools
84	        inputs.agenix.packages."${pkgs.stdenv.hostPlatform.system}".default
85	
86	        # Agent orchestration
87	        inputs.klaus.packages."${pkgs.stdenv.hostPlatform.system}".default
88	
89	        # the valley CLI (S1 integrator verbs: pending/review); ships from the engine repo
90	        inputs.the-valley.packages."${pkgs.stdenv.hostPlatform.system}".valley
91	      ]
92	      ++ lib.optional config.cosmo.antigravity.enable pkgs.antigravity;
93	
94	    programs.zsh.shellAliases = {
95	      rebuild = "if [ -e /etc/NIXOS ]; then sudo nixos-rebuild switch --flake .; else nix run home-manager -- switch --flake .; fi";
96	    };
97	
98	    # Klaus agent orchestration config
99	    home.file.".klaus/config.json".text = builtins.toJSON {
100	      worktree_base = "/tmp/klaus-sessions";
101	      clone_base = "/home/${config.home.username}/hack";
102	      default_budget = "5.00";
103	      data_ref = "refs/klaus/data";
104	      default_branch = "main";
105	      trusted_reviewers = [ "gemini-code-assist[bot]" ];
106	      auto_merge_on_approval = true;
107	      webhook = {
108	        port = 9800;
109	        path = "/webhook/github";
110	        poll_fallback = config.cosmo.klaus.pollFallback;
111	        relay_url = "https://classic-laddie.coin-inconnu.ts.net";
112	        secret_file = "/run/agenix/github-webhook-secret";
113	      };
114	    };
115	
116	    # Daily standalone home-manager rebuild from cosmo upstream (the
117	    # standalone-home-manager analogue of NixOS `system.autoUpgrade`, for
118	    # non-NixOS hosts). Uses a systemd *user* timer; the rebuild pulls the latest
119	    # flake from GitHub (--refresh), so no local clone is required, mirroring the
120	    # `update` shell alias.
121	    systemd.user = lib.mkIf config.cosmo.standaloneHomeManager.autoUpgrade.enable (
122	      let
123	        upgradeScript = pkgs.writeShellScript "cosmo-home-autoupgrade" ''
124	          set -euo pipefail
125	
126	          # Belt-and-suspenders: never run on NixOS. There `system.autoUpgrade`
127	          # already manages home-manager; a standalone switch here would create a
128	          # competing, NixOS-unmanaged generation. No-op cleanly if enabled by
129	          # mistake.
130	          if [ -e /etc/NIXOS ]; then
131	            echo "cosmo-home-autoupgrade: running on NixOS — use system.autoUpgrade instead; skipping."
132	            exit 0
133	          fi
134	
135	          # Resolve the target inside the script so $(hostname -s) is not baked
136	          # into the Nix store path. PATH and NIX_SSL_CERT_FILE are supplied by
137	          # the unit's Environment= (see below) — systemd user services do not
138	          # source the shell profile, so we set them declaratively rather than
139	          # probing for them at runtime.
140	          HOSTNAME=$(hostname -s)
141	          TARGET="${config.cosmo.standaloneHomeManager.autoUpgrade.flakeRef}#${config.home.username}@$HOSTNAME"
142	          echo "cosmo-home-autoupgrade: rebuilding from $TARGET"
143	          exec home-manager switch --no-write-lock-file --refresh --flake "$TARGET"
144	        '';
145	      in
146	      {
147	        services.cosmo-home-autoupgrade = {
148	          Unit.Description = "Rebuild standalone home-manager from cosmo upstream";
149	          Service = {
150	            Type = "oneshot";
151	            # systemd *user* services start with a minimal environment and do NOT
152	            # source the shell profile / /etc/profile.d/nix.sh, so the Nix env the
153	            # installer wires into the shell is absent. Supply it declaratively:
154	            #   PATH               so `nix`/`home-manager` (in the user profile) resolve
155	            #   NIX_SSL_CERT_FILE  so client-side TLS works when fetching the flake
156	            #                      from GitHub (pkgs.cacert is the same CA bundle
157	            #                      nixpkgs uses everywhere; %h is systemd's $HOME).
158	            Environment = [
159	              "PATH=%h/.nix-profile/bin:/nix/var/nix/profiles/default/bin:/usr/bin:/bin"
160	              "NIX_SSL_CERT_FILE=${pkgs.cacert}/etc/ssl/certs/ca-bundle.crt"
161	            ];
162	            ExecStart = "${upgradeScript}";
163	          };
164	        };
165	        timers.cosmo-home-autoupgrade = {
166	          Unit.Description = "Daily standalone home-manager rebuild from cosmo upstream";
167	          Timer = {
168	            OnCalendar = config.cosmo.standaloneHomeManager.autoUpgrade.onCalendar;
169	            Persistent = true; # catch up if the machine was off at the scheduled time
170	            RandomizedDelaySec = "30m";
171	          };
172	          Install.WantedBy = [ "timers.target" ];
173	        };
174	      }
175	    );
176	  };
177	}
